const inputType = $('Webhook').first().json.input_type;

let text;

if (inputType === 'url') {
  const jinaData = $('Jina Scrape').first().json;
  text = jinaData.body || jinaData.data || jinaData.content || JSON.stringify(jinaData);
} else {
  text = $('Webhook').first().json.content;
}

const truncatedText = String(text || 'No content extracted').trim().slice(0, 4000);

return [{ json: { text_to_analyse: truncatedText } }];

// Parse the LLM JSON response and clean it if needed
const llmOutput = $('LLM Analysis').first().json;
const rawContent = llmOutput.choices[0].message.content;

// Strip markdown code fences if LLM added them despite instructions
const cleaned = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  // Fallback if JSON is still malformed
  parsed = {
    score_global: 0,
    intensite: 'low',
    techniques: [],
    synthese: 'Analysis could not be parsed. Please try again with a shorter text.'
  };
}

return [{ json: parsed }];
